/**
 * Bx4 -- Briefings View
 * Daily/weekly briefings generated by the advisor.
 */

'use strict';

async function initBriefings() {
    var root = document.getElementById('view-root');
    var co = window.BX4.currentCompany;
    if (!co) { root.innerHTML = '<div class="empty-state"><div class="empty-state-title">Select a company</div></div>'; return; }

    root.innerHTML = buildBriefingsShell(co);

    try {
        var data = await companyApi('/briefings?limit=20');
        renderBriefingsList(data);
    } catch (err) {
        document.getElementById('briefings-list').innerHTML =
            '<div class="text-sm" style="color:var(--danger);">Failed to load briefings: ' + esc(err.message) + '</div>';
    }
}

function buildBriefingsShell(co) {
    return '' +
        '<div class="view-header">' +
            '<div><h1 class="view-title">Briefings</h1>' +
            '<div class="view-subtitle">' + esc(co.name) + '</div></div>' +
            '<div style="display:flex;gap:8px;">' +
                '<button class="btn btn-outline" onclick="generateBriefing(\'daily\')">Generate Daily Briefing</button>' +
                '<button class="btn btn-primary" onclick="generateBriefing(\'weekly\')">Generate Weekly Briefing</button>' +
            '</div>' +
        '</div>' +

        '<div class="card">' +
            '<div class="card-header"><h3>Recent Briefings</h3></div>' +
            '<div class="card-body" id="briefings-list"><div class="spinner"></div></div>' +
        '</div>';
}

function renderBriefingsList(data) {
    var el = document.getElementById('briefings-list');
    var items = data && data.briefings ? data.briefings : (Array.isArray(data) ? data : []);

    if (items.length === 0) {
        el.innerHTML =
            '<div class="empty-state" style="padding:40px;">' +
                '<span class="empty-state-icon">&#x1F4CB;</span>' +
                '<div class="empty-state-title">No briefings yet</div>' +
                '<div class="empty-state-msg">Generate your first daily or weekly briefing.</div>' +
            '</div>';
        return;
    }

    var html = '<div class="action-list">';
    items.forEach(function(item, idx) {
        var typeBadge = item.type === 'weekly'
            ? '<span class="badge badge-info">WEEKLY</span>'
            : '<span class="badge badge-neutral">DAILY</span>';
        var discordBadge = item.dispatched_discord ? '<span class="badge badge-success" style="font-size:10px;">Discord ✓</span> ' : '';
        var emailBadge   = item.dispatched_email   ? '<span class="badge badge-success" style="font-size:10px;">Email ✓</span> ' : '';

        html += '<div class="action-item">' +
            '<div class="action-item-body" style="cursor:pointer;" onclick="toggleBriefingDetail(' + idx + ')">' +
                '<div class="action-item-title">' + typeBadge + ' ' + esc(item.title || fmtDate(item.created_at)) + '</div>' +
                '<div class="action-item-summary">' + esc(item.summary || '') + '</div>' +
                '<div class="text-sm text-muted mt-8">' + fmtDateTime(item.created_at) + ' &mdash; ' + discordBadge + emailBadge + '</div>' +
                '<div id="briefing-detail-' + idx + '" class="hidden" style="margin-top:12px;padding-top:12px;border-top:1px solid var(--border);white-space:pre-wrap;font-size:13px;color:var(--text-2);line-height:1.7;">' +
                    esc(item.content || item.body || 'No detailed content available.') +
                '</div>' +
            '</div>' +
            '<div class="action-item-actions" style="flex-direction:column;gap:4px;">' +
                '<button class="btn btn-sm btn-ghost" onclick="printBriefing(' + idx + ')" title="Print / Save PDF">&#x1F5A8;</button>' +
                (!item.dispatched_discord ? '<button class="btn btn-sm btn-ghost" onclick="dispatchBriefing(\'' + esc(item.id) + '\', \'discord\')" title="Send to Discord">&#x1F4AC;</button>' : '') +
                (!item.dispatched_email ? '<button class="btn btn-sm btn-ghost" onclick="promptEmailDispatch(\'' + esc(item.id) + '\')" title="Send via Email">&#x2709;</button>' : '') +
            '</div>' +
        '</div>';
    });
    html += '</div>';
    el.innerHTML = html;

    // Store items for print access
    window._bx4Briefings = items;
}

function toggleBriefingDetail(idx) {
    var el = document.getElementById('briefing-detail-' + idx);
    if (el) el.classList.toggle('hidden');
}

async function generateBriefing(type) {
    showToast('Generating ' + type + ' briefing...', 'info');
    try {
        await companyApi('/briefings/generate', {
            method: 'POST',
            body: { type: type }
        });
        showToast(type.charAt(0).toUpperCase() + type.slice(1) + ' briefing generated', 'success');
        initBriefings();
    } catch (err) {
        showToast('Failed: ' + err.message, 'error');
    }
}

function printBriefing(idx) {
    var items = window._bx4Briefings || [];
    var item = items[idx];
    if (!item) return;
    var win = window.open('', '_blank');
    win.document.write(
        '<html><head><title>' + (item.title || 'Briefing') + '</title>' +
        '<style>body{font-family:system-ui,sans-serif;max-width:700px;margin:40px auto;line-height:1.6;color:#111;}h1{font-size:18px;margin-bottom:8px;}pre{white-space:pre-wrap;font-family:inherit;}</style>' +
        '</head><body>' +
        '<h1>' + (item.title || 'Briefing') + '</h1>' +
        '<p style="color:#666;font-size:13px;">' + (item.created_at ? new Date(item.created_at).toLocaleString() : '') + ' &mdash; ' + (item.type || 'daily') + '</p>' +
        '<pre>' + (item.content || '').replace(/</g, '&lt;') + '</pre>' +
        '</body></html>'
    );
    win.document.close();
    win.print();
}

async function dispatchBriefing(briefingId, channel, toEmail) {
    showToast('Dispatching to ' + channel + '...', 'info');
    try {
        var body = { channel: channel };
        if (toEmail) body.to_email = toEmail;
        await companyApi('/briefings/' + briefingId + '/dispatch', { method: 'POST', body: body });
        showToast('Dispatched to ' + channel, 'success');
        initBriefings();
    } catch (err) {
        showToast('Dispatch failed: ' + err.message, 'error');
    }
}

function promptEmailDispatch(briefingId) {
    var email = prompt('Send briefing to email address:');
    if (!email) return;
    dispatchBriefing(briefingId, 'email', email.trim());
}

// Expose globally
window.toggleBriefingDetail = toggleBriefingDetail;
window.generateBriefing     = generateBriefing;
window.printBriefing        = printBriefing;
window.dispatchBriefing     = dispatchBriefing;
window.promptEmailDispatch  = promptEmailDispatch;
